1	/** A live cell's position on an infinite grid, expressed as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
5	  [-1, -1], [-1, 0], [-1, 1],
6	  [ 0, -1],          [ 0, 1],
7	  [ 1, -1], [ 1, 0], [ 1, 1],
8	];
9	
10	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
11	
12	const countLiveNeighbors = (cell: Cell, livingKeys: ReadonlySet<string>): number =>
13	  NEIGHBOR_OFFSETS.filter(([dx, dy]) =>
14	    livingKeys.has(cellKey([cell[0] + dx, cell[1] + dy])),
15	  ).length;
16	
17	/**
18	 * Applies Conway's Game of Life rules to the given live cells and returns
19	 * the next generation. Dead cells are implicit: any coordinate not listed is dead.
20	 */
21	export function nextGeneration(liveCells: Cell[]): Cell[] {
22	  const livingKeys = new Set(liveCells.map(cellKey));
23	  return liveCells.filter((cell) => {
24	    const neighbors = countLiveNeighbors(cell, livingKeys);
25	    return neighbors === 2 || neighbors === 3;
26	  });
27	}
